const motoboys = $input.all();
const webhookData = $('Webhook Inventro').first().json.body;
const data = webhookData.data;

const order = data.order_number || '';
const endereco = data.cliente_endereco || 'Endereco nao informado';
const totalNum = data.total ? Number(data.total).toFixed(2).replace('.', ',') : '0,00';
const pagamento = data.forma_pagamento || '';
const pagMap = { dinheiro: 'Dinheiro', cartao: 'Cartao', pix: 'PIX' };
const pagLabel = pagMap[pagamento] || pagamento;

const msg = '\ud83c\udd95 *Pedido Pronto para Coleta!*\n'
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n'
  + '\ud83d\udccb Pedido *#' + order + '*\n'
  + '\ud83d\udccd ' + endereco + '\n'
  + '\ud83d\udcb0 Valor: *R$ ' + totalNum + '*\n'
  + (pagLabel ? '\ud83d\udcb3 Pagamento: ' + pagLabel + '\n' : '')
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n'
  + 'Acesse o app para aceitar a entrega! \ud83d\ude80';

// Normaliza telefone BR: adiciona 55 se necessario
function normalizarTelefone(tel) {
  let digits = (tel || '').toString().replace(/\D/g, '');
  if (!digits) return '';
  // Se ja tem 55 + 11 digitos = 13, ok
  if (digits.length === 13 && digits.startsWith('55')) return digits;
  // Se tem 12 e comeca com 55, pode ser fixo sem 9
  if (digits.length === 12 && digits.startsWith('55')) {
    const ddd = digits.substring(2, 4);
    const num = digits.substring(4);
    if (num[0] !== '9') return '55' + ddd + '9' + num;
    return digits;
  }
  // 11 digitos (DDD + 9 + 8) -> adiciona 55
  if (digits.length === 11) return '55' + digits;
  // 10 digitos (DDD + 8 fixo) -> adiciona 55 + 9
  if (digits.length === 10 && digits[2] !== '9') return '55' + digits.substring(0, 2) + '9' + digits.substring(2);
  return digits;
}

return motoboys.map(m => {
  const telefone = normalizarTelefone(m.json.telefone);
  const telefoneValido = /^55\d{2}9\d{8}$/.test(telefone);

  if (!telefoneValido) {
    return { json: { telefone: '', nome: m.json.nome, mensagem: '', erro: 'Telefone invalido ou ausente: ' + (m.json.telefone || '(vazio)') + ' -> ' + telefone, enviar: false } };
  }

  return { json: { telefone: telefone, nome: m.json.nome, mensagem: msg, enviar: true } };
});
